content:
@media (max-width: 900px){
    #main-wrap{flex-direction:column}
    #left-rail{width:100%;border-right:none;border-bottom:1px solid var(--border);flex-direction:row;align-items:stretch;justify-content:space-between;padding:10px 12px;overflow-x:auto}
    .rail-brand{width:auto;min-width:72px;border-bottom:none;border-right:1px solid var(--border);padding:0 12px 0 0}
    .rail-nav{width:auto;flex-direction:row}
    .rail-btn{min-width:74px;min-height:52px}
    .rail-spacer{display:none}
    .rail-mode{width:auto;border-top:none;border-left:1px solid var(--border);padding:0 0 0 12px;align-items:center}
    #activity-panel.open{width:100%;max-height:320px;border-left:none;border-top:1px solid var(--border)}
  }
